"""UI Registration - Negative test cases (auto-generated by ASTRA, pytest-playwright)."""
import pytest
from playwright.sync_api import Page, expect


@pytest.mark.ui
@pytest.mark.negative
def test_registration_submit_empty_form(authenticated_page: Page):
    """Submitting empty form shows validation errors."""
    page = authenticated_page
    import os
    page.goto(os.getenv("TARGET_PAGE_URL", "/register"))
    page.wait_for_load_state("networkidle")
    page.click("[type=submit], button:has-text('Register'), button:has-text('Submit')")
    error = page.query_selector(".error, [data-testid=error], [aria-invalid=true], :invalid")
    assert error is not None, "Validation errors should appear on empty submit"


@pytest.mark.ui
@pytest.mark.negative
def test_registration_invalid_email_format(authenticated_page: Page):
    """Invalid email format triggers inline error."""
    page = authenticated_page
    import os
    page.goto(os.getenv("TARGET_PAGE_URL", "/register"))
    page.fill("[type=email], [name=email]", "not-an-email")
    page.click("[type=submit], button:has-text('Register')")
    error = page.query_selector(".error, [data-testid=error], [aria-invalid=true]")
    assert error is not None
    assert "success" not in page.url


