@pytest.mark.ui
@pytest.mark.negative
def test_registration_mismatched_passwords(authenticated_page: Page):
    """Mismatched confirm password triggers error."""
    page = authenticated_page
    import os
    page.goto(os.getenv("TARGET_PAGE_URL", "/register"))
    page.fill("[type=password], [name=password]", "Secure@123")
    confirm = page.query_selector("[name=confirmPassword], #confirmPassword")
    if confirm:
        confirm.fill("Different@456")
    page.click("[type=submit], button:has-text('Register')")
    assert "success" not in page.url


@pytest.mark.ui
@pytest.mark.negative
def test_registration_sql_injection_in_name(authenticated_page: Page):
    """SQL injection in name field is safely handled."""
    page = authenticated_page
    import os
    page.goto(os.getenv("TARGET_PAGE_URL", "/register"))
    page.fill("[name=firstName], #firstName", "'; DROP TABLE users; --")
    page.fill("[type=email], [name=email]", "sql@test.com")
    page.fill("[type=password], [name=password]", "Secure@123")
    page.click("[type=submit], button:has-text('Register')")
    # Should either show error or handle gracefully - not crash
    assert page.query_selector("body") is not None
